// GERADOR DE LABIRINTO PROCEDURAL (fases 11+)
// Algoritmo: Recursive Backtracker
// ==============================
function embaralhar(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function gerarLabirintoProcedural(fase) {
  const crescimento = Math.min(fase - 11, 8);
  let numCols = 27 + crescimento * 2;
  let numLins = 21 + crescimento * 2;
  if (numCols % 2 === 0) numCols++;
  if (numLins % 2 === 0) numLins++;

  const mapa = [];
  for (let l = 0; l < numLins; l++) {
    mapa.push(new Array(numCols).fill(1));
  }

  function escavar(l, c) {
    const dirs = embaralhar([[-2,0],[2,0],[0,-2],[0,2]]);
    mapa[l][c] = 0;
    for (const [dl, dc] of dirs) {
      const nl = l + dl, nc = c + dc;
      if (nl > 0 && nl < numLins-1 && nc > 0 && nc < numCols-1 && mapa[nl][nc] === 1) {
        mapa[l + dl/2][c + dc/2] = 0;
        escavar(nl, nc);
      }
    }
  }
  escavar(1, 1);

  // Passagens extras (menos nas fases avançadas = mais difícil)
  const extras = Math.max(1, 6 - Math.floor((fase - 11) / 2));
  for (let i = 0; i < extras; i++) {
    const l = 1 + Math.floor(Math.random() * Math.floor((numLins-2)/2)) * 2;
    const c = 1 + Math.floor(Math.random() * Math.floor((numCols-2)/2)) * 2;
    const dirs = [[0,1],[1,0],[0,-1],[-1,0]];
    const [dl, dc] = dirs[Math.floor(Math.random() * 4)];
    const nl = l+dl, nc = c+dc;
    if (nl>0 && nl<numLins-1 && nc>0 && nc<numCols-1) mapa[nl][nc] = 0;
  }

  const kl = numLins - 2;
  const kc = Math.floor(numCols / 2);
  mapa[kl][kc]   = 0;
  mapa[kl-1][kc] = 0;

  const pl = numLins - 2;
  const pc = numCols - 2;
  mapa[pl][pc]   = 0;
  mapa[pl-1][pc] = 0;

  return { mapa, numLins, numCols, jl:1, jc:1, kl, kc, pl, pc };
}

// ==============================
// VARIÁVEIS DO JOGO
// ==============================
const canvas = document.getElementById('canvas');
const ctx    = canvas.getContext('2d');

const TAMANHO_CELULA = 40;
const PAREDE  = 1;
const CAMINHO = 0;

let faseAtual       = 1;
let mapaAtual       = [];
let jogador         = { linha: 1, coluna: 1, temChave: false };
let chave           = { linha: 0, coluna: 0, visivel: true };
let porta           = { linha: 0, coluna: 0 };
let pontuacao       = 0;
let melhorPontuacao = 0;
let tempoDecorrido  = 0;
let intervaloTempo  = null;
let jogoAtivo       = false;
let animacaoChave   = 0;
let ultimoMovimento = 0;

// ==============================
// TELA INICIAL
// ==============================
function gerarEstrelas() {
  const container = document.getElementById('estrelasBg');
  for (let i = 0; i < 60; i++) {
    const estrela = document.createElement('div');
    estrela.className = 'estrela';
    estrela.style.left            = Math.random() * 100 + '%';
    estrela.style.top             = Math.random() * 100 + '%';
    estrela.style.animationDelay    = Math.random() * 2 + 's';
    estrela.style.animationDuration = (1.5 + Math.random() * 2) + 's';
    container.appendChild(estrela);
  }
}

function iniciarJogo() {
  document.getElementById('telaInicial').style.display = 'none';
  document.getElementById('telaJogo').classList.add('ativo');
  document.getElementById('btnAjuda').classList.add('visivel');
  document.getElementById('modalInstrucoes').classList.remove('oculto');
  faseAtual = 1;
  pontuacao = 0;
  carregarFase(1);
}

// ==============================
// CARREGAR FASE
// ==============================
function carregarFase(indice) {
  let dados;

  if (indice <= nivelFixo.length) {
    // Fase fixa (1-10)
    const n = nivelFixo[indice - 1];
    dados = {
      mapa: n.mapa,
      numLins: n.mapa.length,
      numCols: n.mapa[0].length,
      jl: n.jl, jc: n.jc,
      kl: n.kl, kc: n.kc,
      pl: n.pl, pc: n.pc
    };
  } else {
    // Fase procedural (11+)
    dados = gerarLabirintoProcedural(indice);
  }

  mapaAtual = dados.mapa;
  jogador   = { linha: dados.jl, coluna: dados.jc, temChave: false };
  chave     = { linha: dados.kl, coluna: dados.kc, visivel: true };
  porta     = { linha: dados.pl, coluna: dados.pc };

  jogoAtivo      = true;
  tempoDecorrido = 0;

  const maxLargura = Math.min(window.innerWidth, 700);
  const maxAltura  = window.innerHeight - 60;
  const escala     = Math.min(
    maxLargura / (dados.numCols * TAMANHO_CELULA),
    maxAltura  / (dados.numLins * TAMANHO_CELULA)
  );
  const tc = Math.max(16, Math.floor(TAMANHO_CELULA * escala));
  canvas.width  = dados.numCols * tc;
  canvas.height = dados.numLins * tc;
  canvas._tc    = tc;

  const labelFase = indice <= 10
    ? 'FASE ' + indice + ' / 10'
    : 'FASE ' + indice + ' ♾';
  document.getElementById('hudFase').textContent  = labelFase;
  document.getElementById('hudChave').textContent = 'SEM CHAVE';
  atualizarHud();

  if (intervaloTempo) clearInterval(intervaloTempo);
  intervaloTempo = setInterval(tickTempo, 1000);

  requestAnimationFrame(loopJogo);
}

function tickTempo() {
  if (!jogoAtivo) return;
  tempoDecorrido++;
  const min = String(Math.floor(tempoDecorrido / 60)).padStart(2, '0');
  const seg = String(tempoDecorrido % 60).padStart(2, '0');
  document.getElementById('hudTempo').textContent = '⏱ ' + min + ':' + seg;
}

function atualizarHud() {
  document.getElementById('hudPontos').textContent = 'PONTOS: ' + pontuacao;
  document.getElementById('hudMelhor').textContent = 'MELHOR: ' + melhorPontuacao;
  document.getElementById('hudChave').textContent  = jogador.temChave ? '✨ COM CHAVE' : 'SEM CHAVE';
}

// ==============================
// LOOP DO JOGO
// ==============================
function loopJogo(agora) {
  if (!jogoAtivo) return;
  animacaoChave = Math.sin(agora / 300) * 4;
  desenharCenario();
  requestAnimationFrame(loopJogo);
}

// ==============================
// DESENHO
// ==============================
function desenharCenario() {
  const tc   = canvas._tc || TAMANHO_CELULA;
  const mapa = mapaAtual;
  ctx.clearRect(0, 0, canvas.width, canvas.height);

  for (let l = 0; l < mapa.length; l++) {
    for (let c = 0; c < mapa[l].length; c++) {
      const x = c * tc, y = l * tc;
      if (mapa[l][c] === PAREDE) desenharPedra(x, y, tc);
      else                        desenharChao(x, y, tc);
    }
  }

  // Porta
  const px = porta.coluna * tc;
  const py = porta.linha  * tc;
  if (jogador.temChave) {
    ctx.shadowColor = '#ffd700';
    ctx.shadowBlur  = 14;
  }
  ctx.drawImage(imagemPorta, px + tc * 0.05, py + tc * 0.02, tc * 0.9, tc * 0.96);
  ctx.shadowBlur = 0;

  // Chave pulando
  if (chave.visivel) {
    const cx2 = chave.coluna * tc + tc / 2;
    const cy2 = chave.linha  * tc + tc / 2 + animacaoChave;
    ctx.save();
    ctx.shadowColor = '#ffd700';
    ctx.shadowBlur  = 12;
    ctx.drawImage(imagemChave, cx2 - tc*0.32, cy2 - tc*0.32, tc*0.64, tc*0.64);
    ctx.restore();
  }

  // Peach
  const jx = jogador.coluna * tc;
  const jy = jogador.linha  * tc;
  ctx.save();
  if (jogador.temChave) {
    ctx.shadowColor = '#f48fb1';
    ctx.shadowBlur  = 16;
  }
  const alturaExibida  = tc * 1.2;
  const larguraExibida = alturaExibida * (372 / 712);
  const offsetX = (tc - larguraExibida) / 2;
  ctx.drawImage(imagemPeach, jx + offsetX, jy - tc * 0.15, larguraExibida, alturaExibida);
  ctx.restore();
}

function desenharPedra(x, y, tc) {
  ctx.fillStyle = '#3d3530';
  ctx.fillRect(x, y, tc, tc);
  const meia   = Math.floor(tc / 2);
  const offset = (Math.floor(y / tc) % 2) * meia;
  ctx.fillStyle = '#4a3f35';
  ctx.fillRect(x + (offset % tc),          y + 2,        meia - 2, meia - 2);
  ctx.fillRect(x + ((offset + meia) % tc), y + meia + 2, meia - 2, meia - 2);
  ctx.strokeStyle = '#1a1612';
  ctx.lineWidth   = 1;
  ctx.strokeRect(x, y, tc, tc);
  ctx.fillStyle = '#5a4e4422';
  ctx.fillRect(x + 2, y + 2, meia - 4, 3);
}

function desenharChao(x, y, tc) {
  ctx.fillStyle = '#1e1714';
  ctx.fillRect(x, y, tc, tc);
  ctx.fillStyle = '#221a1622';
  for (let i = 0; i < 3; i++) {
    const ox = ((x * 3) + i * 13) % Math.max(1, tc - 4);
    const oy = ((y * 3) + i * 7)  % Math.max(1, tc - 4);
    ctx.fillRect(x + ox, y + oy, 2, 2);
  }
}

// ==============================
// MOVIMENTAÇÃO
// ==============================
document.addEventListener('keydown', (e) => {
  if (['ArrowUp','ArrowDown','ArrowLeft','ArrowRight',' '].includes(e.key)) e.preventDefault();
  if (!jogoAtivo) return;
  processarMovimento(e.key, e.shiftKey);
});

function processarMovimento(tecla, correndo) {
  const agora  = Date.now();
  const atraso = correndo ? 100 : 180;
  if (agora - ultimoMovimento < atraso) return;
  ultimoMovimento = agora;

  let novaLinha  = jogador.linha;
  let novaColuna = jogador.coluna;

  if (tecla === 'ArrowUp'    || tecla === 'w' || tecla === 'W') novaLinha--;
  if (tecla === 'ArrowDown'  || tecla === 's' || tecla === 'S') novaLinha++;
  if (tecla === 'ArrowLeft'  || tecla === 'a' || tecla === 'A') novaColuna--;
  if (tecla === 'ArrowRight' || tecla === 'd' || tecla === 'D') novaColuna++;

  if (novaLinha === jogador.linha && novaColuna === jogador.coluna) return;

  const mapa = mapaAtual;
  if (mapa[novaLinha] && mapa[novaLinha][novaColuna] === CAMINHO) {
    jogador.linha  = novaLinha;
    jogador.coluna = novaColuna;
    verificarColetas();
  }
}

// ==============================
// COLETAS E CONDIÇÕES
// ==============================
function verificarColetas() {
  if (!jogador.temChave && jogador.linha === chave.linha && jogador.coluna === chave.coluna) {
    jogador.temChave = true;
    chave.visivel    = false;
    pontuacao += 100;
    atualizarHud();
    mostrarEfeito('✨ CHAVE ENCONTRADA! +100');
  }

  if (jogador.temChave && jogador.linha === porta.linha && jogador.coluna === porta.coluna) {
    const bonus = Math.max(0, 500 - tempoDecorrido * 3);
    pontuacao += bonus;
    if (pontuacao > melhorPontuacao) melhorPontuacao = pontuacao;
    jogoAtivo = false;
    clearInterval(intervaloTempo);
    mostrarEfeito('🚪 FASE CONCLUÍDA! +' + bonus);
    setTimeout(() => {
      faseAtual++;
      carregarFase(faseAtual);
    }, 1400);
  }
}

function mostrarEfeito(texto) {
  const el = document.createElement('div');
  el.textContent = texto;
  el.style.cssText =
    'position:fixed;top:28%;left:50%;transform:translateX(-50%);' +
    "font-family:'Press Start 2P',monospace;font-size:clamp(8px,1.5vw,12px);" +
    'color:#ffd700;text-shadow:2px 2px 0 #000;pointer-events:none;z-index:400;' +
    'animation:subirSumir 1.3s ease-out forwards;white-space:nowrap;';
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 1300);
}

// ==============================
// BOTÕES
// ==============================
document.getElementById('btnIniciarJogo').addEventListener('click', iniciarJogo);

document.getElementById('btnFecharModal').addEventListener('click', () => {
  document.getElementById('modalInstrucoes').classList.add('oculto');
});

document.getElementById('btnAjuda').addEventListener('click', () => {
  document.getElementById('modalInstrucoes').classList.remove('oculto');
});

document.getElementById('btnReiniciar').addEventListener('click', () => {
  document.getElementById('overlayMensagem').classList.add('oculto');
  faseAtual = 1;
  pontuacao = 0;
  carregarFase(1);
});

window.addEventListener('resize', () => {
  if (jogoAtivo) carregarFase(faseAtual);
});

// ==============================
// INICIALIZAÇÃO
// ==============================
gerarEstrelas();
